sp_instance.widget_parameters:
{
	"html": {
		"value": "<p><link href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/css/all.min.css" rel="stylesheet"></p>
<div class="pulse-carousel">
<div class="carousel-container">
<div class="carousel-slide active">
<div class="tip-icon">💧</div>
<p class="tip-text">Staying hydrated boosts your energy and mental clarity. Drink at least 8 glasses of water daily!</p>
</div>
<div class="carousel-slide">
<div class="tip-icon">🍎</div>
<p class="tip-text">A balanced diet rich in fruits and vegetables strengthens your immune system naturally.</p>
</div>
<div class="carousel-slide">
<div class="tip-icon">😴</div>
<p class="tip-text">Quality sleep (7&ndash;8 hours) improves memory, mood, and overall health. Prioritize rest!</p>
</div>
<div class="carousel-slide">
<div class="tip-icon">💊</div>
<p class="tip-text">Always follow prescription instructions. Never share your medication with others.</p>
</div>
</div>
<button class="carousel-prev"></button> <button class="carousel-next"></button>
<div class="carousel-dots">&nbsp;</div>
</div>
<style>
/* ===== تصميم الكاروسيل ===== */
.pulse-carousel {
  position: relative;
  background: linear-gradient(135deg, #FFFFFF, #FFF5F5);
  border-radius: 32px;
  padding: 40px 30px;
  margin: 48px 0;
  text-align: center;
  box-shadow: 0 8px 20px rgba(0,0,0,0.05);
  border: 1px solid #FEE2E2;
}

.carousel-container {
  position: relative;
  min-height: 180px;
}

.carousel-slide {
  display: none;
  animation: fadeEffect 0.5s ease-in-out;
}

.carousel-slide.active {
  display: block;
}

@keyframes fadeEffect {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

.tip-icon {
  font-size: 48px;
  margin-bottom: 16px;
  color: #E60000; /* لون الإيموجي أحمر */
}

.tip-text {
  font-size: 18px;
  font-weight: 500;
  color: #1E293B;
  line-height: 1.5;
  max-width: 700px;
  margin: 0 auto;
  padding: 0 20px;
}

/* أزرار التنقل */
.carousel-prev, .carousel-next {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  background-color: rgba(230, 0, 0, 0.7);
  color: white;
  border: none;
  border-radius: 50%;
  width: 40px;
  height: 40px;
  cursor: pointer;
  transition: all 0.2s ease;
  z-index: 5;
}

.carousel-prev:hover, .carousel-next:hover {
  background-color: #E60000;
  transform: translateY(-50%) scale(1.05);
}

.carousel-prev {
  left: 15px;
}

.carousel-next {
  right: 15px;
}

/* النقاط (dots) */
.carousel-dots {
  display: flex;
  justify-content: center;
  gap: 10px;
  margin-top: 30px;
}

.dot {
  width: 10px;
  height: 10px;
  background-color: #CBD5E1;
  border-radius: 50%;
  cursor: pointer;
  transition: all 0.2s;
}

.dot.active {
  background-color: #E60000;
  width: 24px;
  border-radius: 8px;
}

/* استجابة للشاشات الصغيرة */
@media (max-width: 768px) {
  .pulse-carousel {
    padding: 30px 20px;
  }
  .tip-text {
    font-size: 15px;
  }
  .carousel-prev, .carousel-next {
    width: 32px;
    height: 32px;
  }
}
</style>",
